// ─────────────────────────────────────────────────────────────
// FONCTION POUR GÉNÉRER TOKEN UNIQUE
// ─────────────────────────────────────────────────────────────

function genererTokenUnique(codeX3, dateAbsence) {
  // Créer un token unique basé sur code X3 + date + timestamp
  const timestamp = Date.now();
  const data = `${codeX3}-${dateAbsence}-${timestamp}`;

  // Simple encodage Base64 (en production, utilisez un vrai JWT ou hash sécurisé)
  const token = Buffer.from(data).toString('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=/g, '');

  return token;
}

// ─────────────────────────────────────────────────────────────
// FONCTION POUR CRÉER LIEN FORMULAIRE
// ─────────────────────────────────────────────────────────────

function creerLienFormulaire(data) {
  const dateAbsence = new Date().toISOString().split('T')[0];
  const token = genererTokenUnique(data.code_poste_salarie, dateAbsence);

  const params = new URLSearchParams({
    token: token,
    code: data.code_poste_salarie,
    nom: `${data.prenom_salarie} ${data.nom_salarie}`,
    date: dateAbsence
  });

  return `${BASE_URL_FORMULAIRE}?${params.toString()}`;
}

