// ════════════════════════════════════════════════════════════
// GESTION AMÉLIORÉE ERREUR 429 TELEGRAM - SYSTÈME DE RETRY ROBUSTE
// ════════════════════════════════════════════════════════════

const inputData = $input.all();
const MAX_RETRIES = 10; // ← MODIFIÉ : Passé de 5 à 10 tentatives
const BASE_WAIT_SECONDS = 35; // Attente de base augmentée (Telegram demande 30s minimum)
const results = [];

for (const item of inputData) {
  const currentRetryCount = item.json.retryCount || 0;
  const error = item.json.error || {};

  // ═══════════════════════════════════════════════════════════
  // DÉTECTION ERREUR 429
  // ═══════════════════════════════════════════════════════════

  // Vérifier différents formats d'erreur 429
  const is429Error = 
    error.httpCode === '429' || 
    error.httpCode === 429 ||
    (typeof error === 'string' && error.includes('429')) ||
    (typeof error === 'string' && error.toLowerCase().includes('too many requests')) ||
    (error.message && error.message.includes('429')) ||
    (error.message && error.message.toLowerCase().includes('too many requests'));

  // ═══════════════════════════════════════════════════════════
  // EXTRACTION DU DÉLAI SUGGÉRÉ PAR TELEGRAM
  // ═══════════════════════════════════════════════════════════

  let telegramSuggestedWait = 0;

  if (is429Error) {
    // Chercher "retry after XX" dans le message d'erreur
    const errorString = typeof error === 'string' ? error : (error.message || '');
    const retryAfterMatch = errorString.match(/retry after (\d+)/i);

    if (retryAfterMatch) {
      telegramSuggestedWait = parseInt(retryAfterMatch[1], 10);
      console.log(`⏱️ Délai suggéré par Telegram: ${telegramSuggestedWait}s`);
    }
  }

  // ═══════════════════════════════════════════════════════════
  // TRAITEMENT ERREUR 429
  // ═══════════════════════════════════════════════════════════

  if (is429Error) {
    const newRetryCount = currentRetryCount + 1;

    console.log('═══════════════════════════════════════════════════════════');
    console.log(`🔄 ERREUR 429 DÉTECTÉE - Tentative ${newRetryCount}/${MAX_RETRIES}`);
    console.log(`Chat ID: ${item.json.messages?.telegram?.chat_id}`);
    console.log(`Destinataire: ${item.json.nom_complet}`);
    console.log(`Type: ${item.json.type_envoi}`);
    console.log('═══════════════════════════════════════════════════════════');

    if (newRetryCount <= MAX_RETRIES) {
      // ─────────────────────────────────────────────────────────
      // CALCUL DU DÉLAI D'ATTENTE PROGRESSIF
      // ─────────────────────────────────────────────────────────

      // Utiliser le délai suggéré par Telegram OU un délai progressif
      let waitSeconds;

      if (telegramSuggestedWait > 0) {
        // Ajouter 5 secondes de marge au délai suggéré par Telegram
        waitSeconds = telegramSuggestedWait + 5;
      } else {
        // Progression exponentielle: 35s, 45s, 60s, 75s, 90s, 105s, 120s, 120s, 120s, 120s
        waitSeconds = Math.min(120, BASE_WAIT_SECONDS + (newRetryCount * 15));
      }

      results.push({
        json: {
          ...item.json,
          retryCount: newRetryCount,
          retryStatus: 'RETRYING',
          waitSeconds: waitSeconds,
          telegramSuggestedWait: telegramSuggestedWait,
          error429: true,
          retryMessage: `Tentative ${newRetryCount}/${MAX_RETRIES} - Attente ${waitSeconds}s`,
          originalError: error,
          errorDetails: {
            errorType: '429_TOO_MANY_REQUESTS',
            errorMessage: typeof error === 'string' ? error : (error.message || 'Unknown error'),
            httpCode: error.httpCode || '429',
            timestamp: new Date().toISOString()
          }
        }
      });

      console.log(`✅ Retry programmé`);
      console.log(`   - Délai suggéré Telegram: ${telegramSuggestedWait}s`);
      console.log(`   - Délai appliqué: ${waitSeconds}s`);
      console.log(`   - Tentative: ${newRetryCount}/${MAX_RETRIES}`);

    } else {
      // ─────────────────────────────────────────────────────────
      // MAXIMUM DE TENTATIVES ATTEINT
      // ─────────────────────────────────────────────────────────

      results.push({
        json: {
          ...item.json,
          retryCount: newRetryCount,
          retryStatus: 'MAX_RETRIES_REACHED',
          error429: true,
          finalError: `Échec après ${MAX_RETRIES} tentatives - Erreur 429 Telegram persistante`,
          originalError: error,
          failureDetails: {
            totalRetries: MAX_RETRIES,
            finalErrorMessage: typeof error === 'string' ? error : (error.message || 'Unknown error'),
            destinataire: item.json.nom_complet,
            chatId: item.json.messages?.telegram?.chat_id,
            bot: item.json.messages?.telegram?.bot,
            typeEnvoi: item.json.type_envoi,
            timestamp: new Date().toISOString()
          }
        }
      });

      console.log('═══════════════════════════════════════════════════════════');
      console.log(`❌ ÉCHEC DÉFINITIF - Maximum de tentatives atteint`);
      console.log(`   - Destinataire: ${item.json.nom_complet}`);
      console.log(`   - Chat ID: ${item.json.messages?.telegram?.chat_id}`);
      console.log(`   - Total tentatives: ${MAX_RETRIES}`);
      console.log('═══════════════════════════════════════════════════════════');
    }

  } else if (error && Object.keys(error).length > 0) {
    // ─────────────────────────────────────────────────────────
    // AUTRE TYPE D'ERREUR (NON 429)
    // ─────────────────────────────────────────────────────────

    results.push({
      json: {
        ...item.json,
        retryStatus: 'OTHER_ERROR',
        error429: false,
        otherError: error,
        errorDetails: {
          errorType: 'NON_429_ERROR',
          errorMessage: typeof error === 'string' ? error : (error.message || 'Unknown error'),
          httpCode: error.httpCode || 'N/A',
          timestamp: new Date().toISOString()
        }
      }
    });

    console.log('═══════════════════════════════════════════════════════════');
    console.log(`⚠️ ERREUR NON-429 DÉTECTÉE`);
    console.log(`   - Type: ${error.httpCode || 'Unknown'}`);
    console.log(`   - Message: ${typeof error === 'string' ? error : (error.message || 'Unknown error')}`);
    console.log(`   - Destinataire: ${item.json.nom_complet}`);
    console.log('═══════════════════════════════════════════════════════════');

  } else {
    // ─────────────────────────────────────────────────────────
    // PAS D'ERREUR - TRANSMISSION NORMALE
    // ─────────────────────────────────────────────────────────

    results.push({
      json: {
        ...item.json,
        retryStatus: 'SUCCESS',
        error429: false,
        successDetails: {
          status: 'MESSAGE_SENT',
          timestamp: new Date().toISOString()
        }
      }
    });
  }
}

// ═══════════════════════════════════════════════════════════
// RAPPORT FINAL
// ═══════════════════════════════════════════════════════════

console.log('\n═══════════════════════════════════════════════════════════');
console.log('📊 RAPPORT TRAITEMENT ERREURS TELEGRAM');
console.log('═══════════════════════════════════════════════════════════');
console.log(`Total items traités: ${results.length}`);
console.log(`  - Retry programmés: ${results.filter(r => r.json.retryStatus === 'RETRYING').length}`);
console.log(`  - Échecs définitifs: ${results.filter(r => r.json.retryStatus === 'MAX_RETRIES_REACHED').length}`);
console.log(`  - Autres erreurs: ${results.filter(r => r.json.retryStatus === 'OTHER_ERROR').length}`);
console.log(`  - Succès: ${results.filter(r => r.json.retryStatus === 'SUCCESS').length}`);
console.log('═══════════════════════════════════════════════════════════\n');

return results;

// Fonction de validation du paramètre Q
function verifierParametreQ(valeur) {
  if (!valeur) {
    return {
      valide: false,
      erreur: "Le paramètre q est manquant"
    };
  }

  // Expression régulière pour vérifier le format S + 4 chiffres
  const regex = /^S\d{4}$/;

  if (!regex.test(valeur)) {
    return {
      valide: false,
      erreur: `Format invalide: "${valeur}". Format attendu: S suivi de 4 chiffres (ex: S0235)`
    };
  }

  const numero = valeur.substring(1);

  return {
    valide: true,
    valeurComplete: valeur,
    lettre: valeur[0],
    numero: numero,
    numeroEntier: parseInt(numero, 10)
  };
}

// Traitement adapté pour la structure de votre webhook
// Les données arrivent sous forme de tableau avec un objet contenant query, body, params, etc.

const inputData = $input.all();

// Initialiser le résultat
let resultat = {
  success: false,
  message: "",
  data: null
};

// Parcourir les données d'entrée
for (const item of inputData) {
  // Extraire le paramètre q depuis query (minuscule comme dans votre exemple)
  const paramQ = item.json.query?.Salarie || item.json.body?.Salarie || item.json.params?.Salarie;

  // Vérifier le paramètre
  const validation = verifierParametreQ(paramQ);

  if (!validation.valide) {
    resultat = {
      success: false,
      message: validation.erreur,
      parametreRecu: paramQ || "aucun",
      sourceData: {
        query: item.json.query,
        body: item.json.body,
        params: item.json.params
      }
    };
  } else {
    resultat = {
      success: true,
      message: "Paramètre validé avec succès",
      data: validation,
      sourceData: {
        query: item.json.query,
        webhookUrl: item.json.webhookUrl,
        executionMode: item.json.executionMode
      }
    };
  }
}

// Retourner le résultat
return resultat;

