// ─────────────────────────────────────────────────────────────
// HELPERS
// ─────────────────────────────────────────────────────────────

function nettoyerTelephone(numeros) {
  if (Array.isArray(numeros)) {
    return numeros.filter(num => num && num.trim() !== '').join(', ');
  }
  return numeros || 'Non renseigné';
}

function getLangue(langueData) {
  if (!langueData) return 'FRA';
  const langue = langueData.toUpperCase();
  return ['FRA', 'ARA', 'ENG'].includes(langue) ? langue : 'FRA';
}

function formaterDate(langue = 'FRA') {
  const date = new Date();
  const locale = langue === 'ARA' ? 'ar-MA' : langue === 'ENG' ? 'en-US' : 'fr-FR';
  return date.toLocaleDateString(locale, { 
    year: 'numeric', 
    month: '2-digit', 
    day: '2-digit'
  });
}

function formaterDateHeure(langue = 'FRA') {
  const date = new Date();
  const locale = langue === 'ARA' ? 'ar-MA' : langue === 'ENG' ? 'en-US' : 'fr-FR';
  return date.toLocaleString(locale, { 
    year: 'numeric', 
    month: '2-digit', 
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit'
  });
}

function formaterDateISO() {
  const date = new Date();
  return date.toISOString().split('T')[0]; // Format YYYY-MM-DD
}

// Récupérer et parser la date depuis le webhook
function getDateAbsenceFromWebhook() {
  try {
    // Récupérer la date depuis le webhook (format: DD/MM/YYYY)
    const webhookData = $('Webhook').first().json;
    const dateStr = webhookData.query.Date; // Ex: "02/01/2026"

    if (!dateStr) {
      return formaterDateISO(); // Fallback sur la date actuelle
    }

    // Parser DD/MM/YYYY vers YYYY-MM-DD
    const parts = dateStr.split('/');
    if (parts.length === 3) {
      const day = parts[0].padStart(2, '0');
      const month = parts[1].padStart(2, '0');
      const year = parts[2];
      return `${year}-${month}-${day}`; // Format ISO: YYYY-MM-DD
    }

    return formaterDateISO(); // Fallback si format incorrect
  } catch (error) {
    console.log('Erreur récupération date webhook:', error);
    return formaterDateISO(); // Fallback en cas d'erreur
  }
}

// Récupérer le numéro de dossier depuis le webhook
function getNumeroDossierFromWebhook() {
  try {
    const webhookData = $('Webhook').first().json;
    const numeroDossier = webhookData.query.ID; // Variable 'n' du webhook

    return numeroDossier || 'N/A'; // Fallback si non fourni
  } catch (error) {
    console.log('Erreur récupération numéro dossier webhook:', error);
    return 'N/A'; // Fallback en cas d'erreur
  }
}

// Formater la date d'absence selon la langue (depuis webhook)
function formaterDateAbsence(langue = 'FRA') {
  try {
    const dateISO = getDateAbsenceFromWebhook(); // Ex: "2026-01-02"
    const [year, month, day] = dateISO.split('-');
    const dateObj = new Date(year, month - 1, day);

    const locale = langue === 'ARA' ? 'ar-MA' : langue === 'ENG' ? 'en-US' : 'fr-FR';
    return dateObj.toLocaleDateString(locale, { 
      year: 'numeric', 
      month: '2-digit', 
      day: '2-digit'
    });
  } catch (error) {
    console.log('Erreur formatage date:', error);
    return formaterDate(langue); // Fallback
  }
}

