// ─────────────────────────────────────────────────────────────

function genererToken(codeX3, dateAbsence, numeroDossier) {
  // Génère un token simple basé sur code X3 + date + numéro dossier + timestamp
  const timestamp = Date.now();
  const baseString = `${codeX3}-${dateAbsence}-${numeroDossier}-${timestamp}`;

  // Simple hash (pour production, utilisez une vraie fonction de hash)
  let hash = 0;
  for (let i = 0; i < baseString.length; i++) {
    const char = baseString.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash; // Convert to 32bit integer
  }

  return Math.abs(hash).toString(36).toUpperCase();
}

function genererURLFormulairePersonnalisee(data, dateAbsence) {
  const numeroDossier = getNumeroDossierFromWebhook();
  const token = genererToken(data.code_x3_salarie, dateAbsence, numeroDossier);
  const nomComplet = `${data.prenom_salarie} ${data.nom_salarie}`;

  // Construction manuelle des paramètres URL (compatible n8n)
  const params = [
    `token=${encodeURIComponent(token)}`,
    `code=${encodeURIComponent(data.code_x3_salarie)}`,
    `nom=${encodeURIComponent(nomComplet)}`,
    `date=${encodeURIComponent(dateAbsence)}`,
    `dossier=${encodeURIComponent(numeroDossier)}`
  ].join('&');

  return {
    url: `${FORMULAIRE_BASE_URL}?${params}`,
    token: token,
    numeroDossier: numeroDossier
  };
}

